INSERT INTO "public"."questions" ("id", "module_id", "question", "options", "answer") VALUES (1, 1, 'Apa kepanjangan dari HTML?', '["HyperText Markup Language","HighText Machine Language","Hyperlink and Text Markup Language"]', 0), (2, 1, 'Tag manakah yang digunakan untuk membuat judul (heading) paling besar?', '["<h6>","<head>","<h1>"]', 2), (3, 1, 'Apa fungsi dari tag <p> dalam HTML?', '["Membuat paragraf","Membuat gambar","Membuat garis"]', 0), (4, 1, 'Manakah tag yang benar untuk membuat hyperlink?', '["<link>","<a>","<href>"]', 1), (5, 1, 'Tag manakah yang digunakan untuk memasukkan gambar?', '["<image>","<src>","<img>"]', 2), (6, 2, 'Seorang siswa menemukan komentar bernada hinaan terhadap temannya di media sosial kelas. Apa tindakan paling etis yang sebaiknya ia lakukan?', '["Mengambil tangkapan layar dan menyebarkannya ke grup lain sebagai contoh buruk","Ikut menambahkan komentar lucu agar suasana lebih ramai","Menghubungi teman yang dihina dan atau melaporkan ke guru serta meminta komentar negatif tersebut untuk dihapus"]', 2), (7, 2, 'Saat mencari materi tugas, seorang siswa menemukan artikel blog tanpa menyebut sumber dan menyalinnya bulat-bulat ke tugasnya. Dari sudut pandang etika berinternet, apa yang seharusnya ia lakukan?', '[" Mencantumkan sumber artikel dan merangkumnya dengan kata-katanya sendiri","Mengabaikan artikel tersebut dan hanya menggunakan buku teks sekolah","Menyalin sebagian besar isi artikel lalu mengubah beberapa kata agar terlihat berbeda"]', 0), (8, 2, 'Seorang pengguna ingin membagikan foto kegiatan sekolah di akun media sosialnya. Apa hal penting terkait etika berinternet yang harus dipertimbangkan sebelum mengunggah foto tersebut?', '[" Memastikan foto terlihat menarik agar mendapatkan banyak suka dan komentar"," Memastikan foto tidak mengandung wajah orang lain yang belum memberikan izin","Memastikan foto diunggah pada jam ramai agar mendapat jangkauan luas"]', 1), (9, 2, 'Dalam sebuah grup diskusi online, salah satu anggota mengirim informasi kesehatan yang terdengar meyakinkan namun tanpa menyertakan sumber resmi. Apa praktik etis yang sebaiknya dilakukan anggota lain sebelum meneruskan informasi tersebut?', '["Memeriksa kebenaran informasi ke sumber resmi","Langsung meneruskan ke semua kontak karena terlihat bermanfaat","Mengomentari bahwa informasi itu pasti benar karena banyak orang membicarakannya"]', 0), (10, 2, 'Seorang remaja sering menggunakan bahasa kasar dan sarkas di forum game online karena merasa semua orang melakukannya. Dari perspektif etika berinternet, apa sikap yang sebaiknya ia kembangkan?', '["Berhenti berbicara sama sekali di forum agar tidak menyinggung siapa pun","Mulai berlatih berbicara tegas tetapi tetap sopan dan menghargai orang lain","Menggunakan bahasa kasar hanya saat marah besar agar lebih lega"]', 1), (11, 3, 'Seorang siswa menulis kalimat: "Hatinya hancur berkeping-keping saat mendengar kabar itu." Majas apa yang digunakan dalam kalimat tersebut?', '["Majas personifikasi","Majas Hiperbola","Majas Metafora"]', 1), (12, 3, 'Dalam pembelajaran majas, guru menjelaskan bahwa majas adalah "gaya bahasa yang menggunakan kata-kata dengan makna kias untuk menambah keindahan dan kekuatan pesan". Fungsi utama majas menurut definisi tersebut adalah…', '["Menghilangkan emosi dari tulisan agar lebih objektif","Menggantikan seluruh kaidah tata bahasa agar lebih bebas","Menambah keindahan dan kekuatan penyampaian pesan"]', 2), (13, 3, 'Seorang penulis menggunakan majas personifikasi dalam kalimat: "Angin berbisik lembut di antara dedaunan." Manfaat penggunaan majas personifikasi dalam kalimat tersebut adalah…

', '["Menghilangkan unsur perasaan dari deskripsi suasana","Menjelaskan sifat fisik angin secara ilmiah dan rinci","Membuat gambaran suasana menjadi lebih hidup dan puitis"]', 2), (14, 3, 'Mengapa mempelajari berbagai jenis majas (seperti metafora, simile, personifikasi, dan hiperbola) penting bagi siswa sekolah menengah?

', '["Karena majas membantu meningkatkan kemampuan menulis kreatif dan apresiasi sastra","Karena majas menggantikan kosakata baku sehingga siswa tidak perlu mempelajarinya","Karena majas membuat semua teks menjadi ilmiah dan bebas nilai subjektif"]', 0), (15, 3, 'Seorang siswa menemukan kalimat: "Ia adalah bintang kelas yang selalu bersinar dalam setiap pelajaran." Majas yang digunakan dan alasan kalimat tersebut efektif adalah…

', '["Majas metafora, karena menyamakan langsung seseorang dengan ''bintang'' untuk menegaskan keunggulannya","Majas personifikasi, karena memberi sifat manusia kepada benda mati","Majas hiperbola, karena menyatakan sesuatu yang sangat berlebihan tanpa tujuan jelas"]', 0), (16, 4, 'What is the most accurate Indonesian meaning of the idiom "break the ice" in the sentence: "The teacher told a joke to break the ice on the first day"?

', '["Marah besar hingga suasana menjadi tegang","Memecahkan kebekuan suasana dan membuat orang lebih santai","Membuat masalah yang kecil menjadi besar"]', 1), (17, 4, 'Dalam percakapan: "Don’t worry too much, it’s not the end of the world", apa padanan makna yang paling tepat dalam bahasa Indonesia?

', '["Jangan terlalu khawatir, ini bukan bencana besar yang mengakhiri segalanya","Kita harus menyerah karena situasi sudah tidak bisa diselamatkan","Dunia benar-benar akan berakhir saat ini"]', 0), (18, 4, 'Apa makna terbaik dalam bahasa Indonesia untuk idiom "spill the beans" dalam konteks: "He finally spilled the beans about the surprise party"?

', '["Akhirnya dia membocorkan rahasia tentang pesta kejutan itu","Akhirnya dia merusak seluruh pesta dan membuat kacau","Akhirnya dia memasak makanan untuk pesta kejutan itu"]', 0), (19, 4, 'Dalam kalimat: "She was over the moon when she got the scholarship", apa terjemahan makna idiom "over the moon" yang paling tepat dalam bahasa Indonesia?

', '["Dia marah karena beasiswa itu memberinya banyak beban","Dia merasa sedih dan kecewa karena hasilnya buruk","Dia sangat senang sekali karena mendapat beasiswa"]', 2), (20, 4, 'What is the closest Indonesian meaning of the idiom "hit the nail on the head" in this situation: "When Rina explained why the project failed, she really hit the nail on the head"?

', '["Mengkritik dengan cara yang kasar","Tepat sekali dalam menjelaskan masalah","Berbicara panjang lebar tanpa inti"]', 1), (21, 5, 'Siapa pencipta bahasa pemrograman Python dan kapan versi pertamanya dirilis?
', '["James Gosling, 1995","Guido van Rossum, 1991","Dennis Ritchie, 1972"]', 1), (22, 5, 'Manakah dari aturan penamaan variabel berikut yang BENAR menurut aturan Python?
', '["nama-variabel = ''John''","nama variabel = ''John''","_nama_variabel = ''John''"]', 2), (23, 5, 'Apa fungsi utama dari indentasi (spasi di awal baris) dalam bahasa Python?
', '["Hanya untuk mempercantik tampilan kode.","Untuk mengakhiri sebuah baris perintah.","Untuk menentukan ruang lingkup (scope) seperti blok kode loop, fungsi, atau kelas."]', 2), (24, 5, 'Manakah di antara tipe data kumpulan (array) berikut yang bersifat terurut namun TIDAK dapat diubah (immutable)?
', '["List","Tuple","Set"]', 1), (25, 5, 'Kata kunci (keyword) apa yang digunakan untuk mendefinisikan sebuah fungsi dalam Python?
', '["function","create","def"]', 2), (26, 6, 'Apa peran utama dari tools AI dalam membantu pekerjaan manusia menurut panduan kita?
', '["Menggantikan peran manusia sepenuhnya dalam segala bidang","Berfungsi sebagai asisten digital yang mempercepat proses berpikir, mencipta, dan mengambil keputusan","Hanya digunakan untuk membuat hiburan seperti musik dan gambar."]', 1), (27, 6, 'jika seorang Arsitek AI ingin membuat slide presentasi secara otomatis hanya dengan memberikan perintah teks (prompt), tool mana yang paling tepat digunakan?
', '["Elevenlabs","GAMMA","Looka"]', 1), (28, 6, 'Manakah dari pilihan berikut yang merupakan tool untuk menghasilkan lagu atau komposisi musik lengkap hanya dari deskripsi teks?', '["Suno atau Udio","TLDV atau Otter","Uizard atau Khroma"]', 0), (29, 6, 'Tool AI apa yang menyediakan platform coding kolaboratif berbasis web dengan AI Copilot bawaan, yang sangat cocok untuk pembelajaran?', '["Deepseek","Writesonic","Replit"]', 2), (30, 6, 'Fitur utama dari tool TLDV dalam kategori "Meeting" adalah...', '["Membuat logo perusahaan secara otomatis.","Mencari makalah penelitian ilmiah secara mendalam.","Otomatis merekam, mentranskrip, dan merangkum meeting Zoom atau Google Meet"]', 2);